const output = [];

for (const item of $input.all()) {
  const html = item.json.data;

  // Split HTML into job listing blocks
  const jobBlocks = html.split('<li').slice(1);

  for (const block of jobBlocks) {
    // Extract job URL
    const jobUrlMatch = block.match(/href="([^"]*linkedin\.com\/jobs\/view[^"]*)"/);
    const jobUrl = jobUrlMatch ? jobUrlMatch[1].trim() : '';

    // Extract company name (handles nested <a> tags)
    const companyMatch = block.match(/class="base-search-card__subtitle[^>]*>(.*?)<\/h4>/s);
    let companyName = '';
    if (companyMatch) {
      const linkMatch = companyMatch[1].match(/<a[^>]*>(.*?)<\/a>/);
      companyName = linkMatch ? linkMatch[1].trim() : companyMatch[1].replace(/<[^>]*>/g, '').trim();
    }

    // ✅ Extract location (handles both <div> and <span>)
    const locationMatch = block.match(/class="job-search-card__location[^>]*>(.*?)<\/(?:div|span)>/);
    const location = locationMatch ? locationMatch[1].trim() : '';

    // Extract date posted
    const dateMatch = block.match(/<time[^>]*datetime="([^"]*)"/);
    const datePosted = dateMatch ? dateMatch[1].trim() : '';

    // Push result if at least job URL exists
    if (jobUrl) {
      output.push({
        json: {
          job_url: jobUrl,
          company_name: companyName,
          location: location,
          date_posted: datePosted
        }
      });
    }
  }
}

return output;

